    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe, modifies both sides symmetrically. No unsafe.
    pub fn build_lists_symmetric_serial(&mut self) {
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        let n = self.elems.len();
        for i in 0..n {
            for j in (i + 1)..n {
                // Split to borrow two distinct mutable elements safely.
                let (left, right) = self.elems.split_at_mut(j);
                let elem_i = &mut left[i];
                let elem_j = &mut right[0];

                if elem_i.criterion(elem_j) < self.cutoff {
                    elem_i.nb.push(j);
                    elem_j.nb.push(i);
                }
            }
        }
    }

    /// Parallel version: compute neighbor lists independently in parallel.
    /// This does not require unsafe or shared mutability.
    pub fn build_lists_parallel(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;
        let elems = &self.elems; // immutable borrow for parallel reads

        let lists: Vec<Vec<usize>> = (0..n)
            .into_par_iter()
            .map(|i| {
                let mut nb = Vec::new();
                for j in 0..n {
                    if i == j {
                        continue;
                    }
                    if elems[i].criterion(&elems[j]) < cutoff {
                        nb.push(j);
                    }
                }
                nb
            })
            .collect();

        for (elem, nb) in self.elems.iter_mut().zip(lists) {
            elem.nb = nb;
        }
    }
}

fn main() {
    let mut a = A {
        elems: vec![
            B {
                r: vec![0.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![1.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![3.0, 0.0, 0.0],
                ..Default::default()
            },
        ],
        cutoff: 2.0, // distance squared
    };

    a.build_lists_symmetric_serial();
    println!("Serial symmetric: {:#?}", a.elems);

    a.build_lists_parallel();
    println!("Parallel: {:#?}", a.elems);
}
"
