{"Cargo.toml":"[package]
name = "critical_section_example"
version = "0.1.0"
edition = "2021"

[dependencies]
critical-section = { version = "1.1", features = ["std"] }
","main.rs":"use std::sync::atomic::{AtomicUsize, Ordering};

// A small counter to show how to replace fetch_add with a critical section.
struct Counter {
    channel_index: AtomicUsize,
}

impl Counter {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replacement for `fetch_add(1, Ordering::Relaxed)` using a critical section.
    ///
    /// The original code used `Relaxed`, which means the increment does not
    /// synchronize with any other memory operations.  The critical section
    /// provides mutual exclusion; it is already an acquire/release boundary
    /// around the whole closure.  Therefore inside the critical section you can
    /// use `Relaxed` (or even a non‑atomic cell) and you get the same semantics
    /// as the original `fetch_add(Relaxed)`.
    fn fetch_add_relaxed(&self) -> usize {
        critical_section::with(|_| {
            let old_val = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old_val + 1, Ordering::Relaxed);
            old_val
        })
    }
}

fn main() {
    let c = Counter::new();

    for _ in 0..5 {
        let prev = c.fetch_add_relaxed();
        println!("previous value: {prev}");
    }
}
"}

