","main.rs":"const PIXELS_PER_SIDE: usize = 8;
const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of 4-byte pixels in-place.
/// Uses unaligned 32-bit loads/stores to swap pixels in one operation.
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);
    if line_bytes.len() < BYTES_PER_PIXEL * 2 {
        return;
    }

    let mut left = 0usize;
    let mut right = line_bytes.len() - BYTES_PER_PIXEL;
    let ptr = line_bytes.as_mut_ptr();

    while left < right {
        unsafe {
            // Read 4 bytes at a time (unaligned) and swap.
            let a = std::ptr::read_unaligned(ptr.add(left) as *const u32);
            let b = std::ptr::read_unaligned(ptr.add(right) as *const u32);
            std::ptr::write_unaligned(ptr.add(left) as *mut u32, b);
            std::ptr::write_unaligned(ptr.add(right) as *mut u32, a);
        }
        left += BYTES_PER_PIXEL;
        right -= BYTES_PER_PIXEL;
    }
}

fn main() {
    const ORIGINAL_BYTES: [u8; BYTES_PER_PIXEL * PIXELS_PER_LINE] = [
        1, 2, 3, 4, // 0
        5, 6, 7, 8, // 1
        9, 10, 11, 12, // 2
        13, 14, 15, 16, // 3
        17, 18, 19, 20, // 4
        21, 22, 23, 24, // 5
        25, 26, 27, 28, // 6
        29, 30, 31, 32, // 7
    ];

    const TARGETED_BYTES: [u8; BYTES_PER_PIXEL * PIXELS_PER_LINE] = [
        29, 30, 31, 32, // 7
        25, 26, 27, 28, // 6
        21, 22, 23, 24, // 5
        17, 18, 19, 20, // 4
        13, 14, 15, 16, // 3
        9, 10, 11, 12, // 2
        5, 6, 7, 8, // 1
        1, 2, 3, 4, // 0
    ];

    let mut mutated_bytes = ORIGINAL_BYTES;
    flip_line(&mut mutated_bytes);

    assert_eq!(mutated_bytes, TARGETED_BYTES);
    println!("Flip successful: {:?}", mutated_bytes);
}
"}

