","main.rs":"use rustyline::{Cmd, DefaultEditor, Event, EventHandler, KeyEvent, Modifiers};
use rustyline::error::ReadlineError;
use rustyline::prompt::DefaultPrompt;

fn main() -> rustyline::Result<()> {
    let mut rl = DefaultEditor::new()?;

    // Bind Ctrl+J to insert a newline without accepting the line
    rl.bind_sequence(
        Event::KeySeq(vec![KeyEvent::new('j', Modifiers::CTRL)]),
        EventHandler::Simple(Cmd::Newline),
    );

    // Main prompt and read‑only continuation prompt
    let prompt = DefaultPrompt::new(">> ", ".. ");

    loop {
        match rl.readline(&prompt) {
            Ok(line) => {
                println!("{line:?}");
            }
            Err(ReadlineError::Interrupted | ReadlineError::Eof) => break,
            Err(err) => {
                eprintln!("Error: {err:?}");
                break;
            }
        }
    }

    Ok(())
}
