impl<T> Array<T> {
    fn linear_index(&self, index: &[usize]) -> usize {
        assert_eq!(index.len(), self.dims.len());
        let mut idx = 0;
        let mut stride = 1;
        for i in (0..self.dims.len()).rev() {
            idx += index[i] * stride;
            stride *= self.dims[i];
        }
        idx
    }

    pub fn iter_mut<'a>(&'a mut self) -> ArrayIteratorFromDynMut<'a, T> {
        let selection_iterators: Vec<Box<dyn ArrayViewIterator>> = self
            .dims
            .iter()
            .map(|&d| Box::new(0..d) as Box<dyn ArrayViewIterator>)
            .collect();
        let current_iterators = selection_iterators.iter().map(|it| it.clone()).collect();
