use std::fs;
use std::io;
use std::path::{Path, PathBuf};

use serde::Deserialize;
use serde_json::Value;

#[derive(Deserialize, Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

fn resolve_refs(value: &mut Value, base_dir: &Path) -> Result<(), Box<dyn Error>> {
    match value {
        Value::Object(map) => {
            // Handle {$ref: "..."}
            if map.len() == 1 {
                if let Some(Value::String(r)) = map.get("$ref") {
                    let (file, pointer) = r.split_once('#').unwrap_or((r.as_str(), ""));
                    let file_path = base_dir.join(file);
                    let contents = fs::read_to_string(&file_path)?;
                    let mut referenced: Value = serde_json::from_str(&contents)?;

                    if !pointer.is_empty() {
                        referenced = referenced
                            .pointer(pointer)
                            .ok_or_else(|| io::Error::new(io::ErrorKind::Other, "pointer not found"))?
                            .clone();
                    }

                    // Resolve nested refs inside the referenced value
                    let new_base = file_path.parent().unwrap_or(base_dir);
                    resolve_refs(&mut referenced, new_base)?;
                    *value = referenced;
                    return Ok(());
                }
            }

            for v in map.values_mut() {
                resolve_refs(v, base_dir)?;
            }
        }
        Value::Array(arr) => {
            for v in arr {
                resolve_refs(v, base_dir)?;
            }
        }
        _ => {}
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    // Create example files so `cargo run` works out of the box.
    let a_json = r#"{
  \"p_list\": [
    \"./a/b/c/def\",
    \"./g/h/i/jkl\"
  ]
}"#;
