}"#;
    fs::write("a.json", a_json)?;
    fs::write("b.json", b_json)?;

    // Read and resolve $ref
    let json_data = fs::read_to_string("b.json")?;
    let mut value: Value = serde_json::from_str(&json_data)?;
    resolve_refs(&mut value, Path::new("."))?;

