/// Trait used to check whether `self` matches a filter of type `F`.
trait MatchesFilter<F> {
    fn matches_filter(&self, filter: &F) -> bool;
}

/// Equality-based matching for leaf types (non-Option).
macro_rules! impl_matches_eq {
    ($($t:ty),* $(,)?) => {
        $(impl MatchesFilter<$t> for $t {
            fn matches_filter(&self, filter: &$t) -> bool {
                self == filter
            }
        })*
    };
}

/// Matching for leaf types when the filter is optional.
macro_rules! impl_matches_option_for_leaf {
    ($($t:ty),* $(,)?) => {
        $(impl MatchesFilter<Option<$t>> for $t {
            fn matches_filter(&self, filter: &Option<$t>) -> bool {
                match filter {
                    None => true,
                    Some(f) => self == f,
                }
            }
        })*
    };
}

/// Recursive matching for Option-wrapped values.
impl<T, F> MatchesFilter<Option<F>> for Option<T>
where
    T: MatchesFilter<F>,
{
    fn matches_filter(&self, filter: &Option<F>) -> bool {
        match filter {
            None => true,
            Some(f) => match self {
                Some(v) => v.matches_filter(f),
                None => false,
            },
        }
    }
}

/// Helper macro to implement matching for structs.
macro_rules! impl_matches_for_struct {
    ($t:ty, $f:ty, { $($field:ident),* $(,)? }) => {
        impl MatchesFilter<$f> for $t {
            fn matches_filter(&self, filter: &$f) -> bool {
                true $( && self.$field.matches_filter(&filter.$field) )*
            }
        }
    };
}

