    ast::{self, AstNode, Use, UseTree},
    SourceFile,
};
use ra_ap_text_edit::TextEditBuilder;

#[derive(Debug, Clone)]
struct UsePath {
    segments: Vec<String>,
    glob: bool,
    rename: Option<String>,
}

fn main() {
    let src = r#"
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};
"#;

    let rewritten = rewrite_imports(src);
    println!("{}", rewritten);
}

/// Rewrite all use items in a file
fn rewrite_imports(src: &str) -> String {
    let parse = SourceFile::parse(src);
    let root = parse.tree();

    let mut edit = TextEditBuilder::default();

    for use_item in root.syntax().descendants().filter_map(Use::cast) {
        if let Some(tree) = use_item.use_tree() {
            let new_text = rewrite_use_item(&use_item, &tree);
            let range = use_item.syntax().text_range();
            edit.replace(range, new_text);
        }
    }

    let edit = edit.finish();
    edit.apply(src.to_string())
}

/// Rewrite a single `use` item
fn rewrite_use_item(use_item: &Use, tree: &UseTree) -> String {
    let mut paths = Vec::new();
    collect_paths(tree, vec![], &mut paths);

    let rewritten: Vec<String> = paths
        .into_iter()
        .map(rewrite_path)
        .map(|p| usepath_to_string(&p))
        .collect();

    let vis = use_item
        .visibility()
        .map(|v| format!("{} ", v.to_string()))
        .unwrap_or_default();

    if rewritten.len() == 1 {
        format!("{}use {};", vis, rewritten[0])
    } else {
        format!("{}use {{{}}};", vis, rewritten.join(", "))
    }
}

/// Collect all leaf paths in a use-tree, with full prefixes
fn collect_paths(tree: &UseTree, prefix: Vec<String>, out: &mut Vec<UsePath>) {
    let mut prefix = prefix;

    if let Some(path) = tree.path() {
        let p = path.to_string();
        let p = p.trim_start_matches("::");
        if !p.is_empty() {
            prefix.extend(p.split("::").map(|s| s.to_string()));
        }
    }

    if tree.star_token().is_some() {
        out.push(UsePath {
            segments: prefix,
            glob: true,
            rename: None,
        });
        return;
    }

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            collect_paths(&child, prefix.clone(), out);
        }
        return;
    }

    let rename = tree.rename().map(|r| r.to_string());

    out.push(UsePath {
        segments: prefix,
        glob: false,
        rename,
    });
}

/// Apply the rewrite rule: vexide::devices::X -> vexide::X
fn rewrite_path(mut p: UsePath) -> UsePath {
    if p.segments.len() >= 2 && p.segments[0] == "vexide" && p.segments[1] == "devices" {
        p.segments.remove(1);
    }
    p
}

/// Convert a UsePath back to a string
fn usepath_to_string(p: &UsePath) -> String {
    let mut s = p.segments.join("::");
    if p.glob {
        if !s.is_empty() {
            s.push_str("::*");
        } else {
            s.push('*');
        }
    }
    if let Some(rename) = &p.rename {
        s.push(' ');
        s.push_str(rename);
    }
    s
}
"}

