    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single = false;
    let mut has_token = false; // tracks token even if empty (e.g. "''")

    for ch in input.chars() {
        match ch {
            '\'' => {
                in_single = !in_single;
                has_token = true; // quote starts/continues a token
            }
            c if c.is_whitespace() && !in_single => {
                if has_token {
                    tokens.push(current);
                    current = String::new();
                    has_token = false;
