trait Parser<'i> {
    type Output<'e>;
    fn parse<'e>(&mut self, input: &mut SStream<'i, 'e>) -> ModalResult<Self::Output<'e>>;
}

// A small "type family" trick for functions.
trait OutputFamily {
    type Output<'e>;
}

struct ParserFn<F, O>(F, PhantomData<O>);

fn parser_fn<O, F>(f: F) -> ParserFn<F, O> {
    ParserFn(f, PhantomData)
}

impl<'i, F, O> Parser<'i> for ParserFn<F, O>
where
    O: OutputFamily,
    F: for<'e> FnMut(&mut SStream<'i, 'e>) -> ModalResult<O::Output<'e>>,
{
