        },
    };

    let parsed = match parser.parse(&mut stateful) {
        Ok(parsed) => parsed,
        Err(e) => panic!("Failed on {input:?}: {e}"),
    };

    println!("Testing: input={input:?}, expected={expected_output:?}, parsed={parsed:?}");
    assert_eq!(&parsed, expected_output);
}

