nix = "0.26"
","main.rs":"use expectrl::spawn;
use nix::unistd::dup;
use std::error::Error;
use std::io::{self, Read, Write};
use std::os::unix::io::FromRawFd;
use std::os::unix::io::AsRawFd;
use std::thread;

fn main() -> Result<(), Box<dyn Error>> {
    // Spawn an interactive shell in a PTY
    let session = spawn("/bin/bash")?;

    // Duplicate the PTY master FD so we can safely read/write from different threads
    let master_fd = session.as_raw_fd();
    let read_fd = dup(master_fd)?;
    let write_fd = dup(master_fd)?;

    let mut reader = unsafe { std::fs::File::from_raw_fd(read_fd) };
    let mut writer = unsafe { std::fs::File::from_raw_fd(write_fd) };

    // Thread that continuously reads PTY output and prints to stdout
    thread::spawn(move || {
        let mut buf = [0u8; 4096];
        loop {
            match reader.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    let _ = io::stdout().write_all(&buf[..n]);
                    let _ = io::stdout().flush();
                }
                Err(e) => {
                    eprintln!("read error: {e}");
                    break;
                }
            }
        }
    });

    // Main thread: forward stdin bytes into the PTY
    let mut stdin = io::stdin();
    let mut buf = [0u8; 1024];
    loop {
        let n = stdin.read(&mut buf)?;
        if n == 0 {
            break;
        }
        writer.write_all(&buf[..n])?;
        writer.flush()?;
    }

    // Keep session alive until stdin closes
    drop(session);
    Ok(())
}
"}

