use futures::FutureExt;
use std::sync::mpsc::{channel, Sender};
use std::thread;

#[derive(Debug)]
struct Context(i32);

// Event carrying a boxed async closure
enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> FnOnce(&'a mut Context) -> BoxFuture<'a, ()> + Send,
        >,
    },
}

// Helper: you pass an async closure, but you must box it at call site
fn with_context_async<F>(sender: &Sender<InnerAsyncEvent>, block: F)
where
    F: for<'a> FnOnce(&'a mut Context) -> BoxFuture<'a, ()> + Send + 'static,
{
    sender
        .send(InnerAsyncEvent::DoWithContext {
            block: Box::new(block),
        })
        .unwrap();
}

#[tokio::main(flavor = "current_thread")]
async fn main() {
    let (tx, rx) = channel();

    // Send async work from this thread
    with_context_async(&tx, |ctx: &mut Context| {
        async move {
            ctx.0 += 1;
            println!("inside async: ctx = {}", ctx.0);
        }
        .boxed()
    });

