        let event = rx.recv().unwrap();
        let mut ctx = Context(0);

        match event {
            InnerAsyncEvent::DoWithContext { block } => {
                // Create a runtime for this thread
                let rt = tokio::runtime::Runtime::new().unwrap();
                rt.block_on(async {
                    block(&mut ctx).await;
                });
            }
        }

        ctx.0
    });

    let final_value = handle.join().unwrap();
    println!("final ctx value: {}", final_value);
