","main.rs":"use std::time::Duration;
use tokio::time::sleep;
use tracing::{info, info_span, Instrument, Span};
use tracing_subscriber::fmt::format::FmtSpan;

#[derive(Clone)]
struct RequestContext {
    parent: Span,
}

// Stage functions may be called on any thread at any time.
// We "rehydrate" the parent span by instrumenting the future with it.
async fn stage1(ctx: RequestContext) {
    async move {
        let stage_span = info_span!("stage1");
        async move {
            info!("stage1 work");
            sleep(Duration::from_millis(80)).await;
        }
        .instrument(stage_span)
        .await;
    }
    .instrument(ctx.parent.clone())
    .await;
}

async fn stage2(ctx: RequestContext) {
    async move {
        let stage_span = info_span!("stage2");
        async move {
            info!("stage2 work");
            upstream().await;
        }
        .instrument(stage_span)
        .await;
    }
    .instrument(ctx.parent.clone())
    .await;
}

#[tracing::instrument]
async fn upstream() {
    info!("upstream request");
    sleep(Duration::from_millis(30)).await;
}

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt()
        .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE)
        .init();

    // Parent span representing the request lifecycle.
    let parent = info_span!("request");
    let ctx = RequestContext { parent };

    let h1 = tokio::spawn(stage1(ctx.clone()));
    let h2 = tokio::spawn(stage2(ctx.clone()));

    let _ = tokio::join!(h1, h2);
}
"}

