[dependencies]
","main.rs":"// A minimal, const-friendly PRNG (SplitMix64) used to generate
// Zobrist seeds at compile time.

const SEED: u64 = 4174800045971885562;

pub static ZOBRIST_SEEDS: [u64; 781] = generate_zobrist_seeds();

// SplitMix64: simple and fast PRNG suitable for generating seeds
// (not cryptographically secure, but fine for Zobrist hashing).
const fn splitmix64_next(mut state: u64) -> (u64, u64) {
    // update state
    state = state.wrapping_add(0x9E3779B97F4A7C15);
    // mix
    let mut z = state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D049BB133111EB);
    z ^= z >> 31;
    (z, state)
}

const fn generate_zobrist_seeds() -> [u64; 781] {
    let mut result = [0u64; 781];
    let mut state = SEED;
    let mut i = 0usize;
    while i < 781 {
        let (val, new_state) = splitmix64_next(state);
        result[i] = val;
        state = new_state;
        i += 1;
    }
    result
}

fn main() {
    // Demonstrate that the array exists and is deterministic.
    println!("First 5 Zobrist seeds:");
    for i in 0..5 {
        println!("{}: {}", i, ZOBRIST_SEEDS[i]);
    }
}
"}

